@startuml

abstract class Pessoa {
  {abstract} nome: String
}

class Ginasio {
  - nome: String
  - quadra: List<Quadra>
}

class Quadra {
  - numero: Int
  - aluguel: Aluguel
  - ginasio: Ginasio
}

class Clients {
  - id: Int
  - nome: String
  - locação: List<Aluguel>
}

class Aluguel {
  - cliente: Client
  - tempo: Int
  - quadra: Quadra
}

Pessoa <|-- Clients

Ginasio "1" *-- "1..*" Quadra

Clients "0" *-- "1..*" Aluguel

Aluguel "1" o-- "1" Pessoa

@enduml
